per_section_results.variation_css:
.sgs-products { display: grid; grid-template-columns: 1fr; gap: 16px }
@media (min-width: 768px) :: .sgs-products { grid-template-columns: 5fr 3fr }
.sgs-featured-product__inner { max-width: 1040px; margin: 0 auto }
.sgs-featured-product { padding: 56px 20px; background: var(--surface-cream) }
.sgs-featured-product__inner { max-width: 1040px; margin: 0 auto }
.sgs-featured-product h2 { font-size: 28px; font-weight: 600; color: var(--text); margin-bottom: 6px }
.sgs-featured-product .sgs-section-heading__intro { font-size: 16px; color: var(--text-muted); margin-bottom: 32px }
.sgs-featured-product__pill-group { display: flex; gap: 7px; flex-wrap: wrap; margin-bottom: 16px }
.sgs-featured-product__pill { background: var(--surface-cream); border: 2px solid var(--border); border-radius: 8px; padding: 7px 13px; font-family: 'Inter', sans-serif; font-size: 13px; font-weight: 600; color: var(--text-muted); cursor: pointer; min-height: 44px; display: flex; align-items: center; transition: all 0.15s; line-height: 1 }
.sgs-featured-product__pill.active { border-color: var(--primary); background: rgba(230,138,149,0.1); color: var(--text) }
.sgs-featured-product__pill:hover:not(.active) { border-color: var(--primary-dark) }
.sgs-featured-product__price-row { display: flex; align-items: baseline; gap: 10px; margin-bottom: 14px }
.sgs-featured-product__price { font-family: 'Fraunces', serif; font-size: 28px; font-weight: 700; color: var(--text) }
.sgs-featured-product__price-note { font-size: 13px; color: var(--text-muted) }
@media (min-width: 768px) :: .sgs-featured-product h2 { font-size: 36px }

.sgs-brand__content { display: flex; flex-direction: column; gap: 16px }
.sgs-brand { background: var(--surface-alt); padding: 64px 20px; max-width: 1000px; margin: 0 auto; display: grid; grid-template-columns: 1fr; gap: 32px }
.sgs-brand__content { display: flex; flex-direction: column; gap: 16px }
.sgs-brand__image { width: 100%; max-height: 380px; object-fit: cover; border-radius: 16px; order: -1 }
.sgs-brand__headline { font-size: 28px; font-weight: 600; color: var(--text); margin-bottom: 20px }
@media (min-width: 768px) :: .sgs-brand { grid-template-columns: 1fr 1fr; gap: 60px; align-items: center }
@media (min-width: 768px) :: .sgs-brand__image { order: 0; max-height: 440px; height: 440px }
@media (min-width: 768px) :: .sgs-brand__headline { font-size: 36px }

.sgs-ingredients-section__inner { max-width: 960px; margin: 0 auto; text-align: center }
.sgs-ingredients-section { background: var(--surface-cream); padding: 64px 20px }
.sgs-ingredients-section__inner { max-width: 960px; margin: 0 auto; text-align: center }
.sgs-ingredients-section h2 { font-size: 28px; font-weight: 600; color: var(--text); margin-bottom: 8px }
.sgs-ingredients-section .sgs-section-heading__intro { font-size: 16px; color: var(--text-muted); margin: 0 auto 36px; max-width: 540px }
.sgs-ingredients-section__disclaimer { font-size: 14px; color: var(--text-muted); font-style: italic; max-width: 620px; margin: 0 auto; padding: 16px 20px; background: white; border-radius: 10px; border: 1px solid var(--border); line-height: 1.55 }
@media (min-width: 600px) :: .sgs-ingredients-section h2 { font-size: 36px }

.sgs-gift-section__cards { display: grid; grid-template-columns: 1fr; gap: 16px; margin-bottom: 20px }
@media (min-width: 640px) :: .sgs-gift-section__cards { grid-template-columns: 1fr 1fr }
.sgs-gift-section__card-inner { max-width: 960px; margin: 0 auto }
.sgs-gift-section__card--trial { border: 2px dashed var(--accent); background: linear-gradient(135deg, rgba(245,208,80,0.08) 0%, rgba(230,138,149,0.06) 100%) }
.sgs-gift-section__card-tag--trial { display: inline-flex; align-items: center; background: var(--accent); color: var(--text); font-size: 11px; font-weight: 700; padding: 4px 10px; border-radius: 6px; letter-spacing: 0.5px; text-transform: uppercase; margin-bottom: 12px }
.sgs-gift-section { background: var(--surface-pink); padding: 64px 20px }
.sgs-gift-section__card-inner { max-width: 960px; margin: 0 auto }
.sgs-gift-section h2 { font-size: 28px; font-weight: 600; color: var(--text); margin-bottom: 8px }
.sgs-gift-section .sgs-section-heading__sub { font-size: 16px; color: var(--text); margin-bottom: 32px }
.sgs-gift-section__cards { display: grid; grid-template-columns: 1fr; gap: 16px; margin-bottom: 20px }
.sgs-gift-section__card { background: white; border-radius: 16px; padding: 28px 24px; border: 1px solid var(--border) }
.sgs-gift-section__card-tag { display: inline-block; background: var(--surface-pink); color: var(--primary-dark); font-size: 11px; font-weight: 700; padding: 4px 10px; border-radius: 6px; letter-spacing: 0.5px; text-transform: uppercase; margin-bottom: 12px }
.sgs-gift-section__card h3 { font-size: 22px; font-weight: 600; color: var(--text); margin-bottom: 8px }
.sgs-gift-section__card .sgs-gift-section__card-description { font-size: 14px; color: var(--text-muted); margin-bottom: 20px; line-height: 1.6 }
.sgs-gift-section__card .sgs-gift-section__card-price { font-family: 'Fraunces', serif; font-size: 30px; font-weight: 700; color: var(--text); margin-bottom: 16px }
@media (min-width: 640px) :: .sgs-gift-section__cards { grid-template-columns: 1fr 1fr }
@media (min-width: 640px) :: .sgs-gift-section h2 { font-size: 36px }

.sgs-social-proof__trustpilot-bar { background: white; border: 1px solid var(--border); border-radius: 10px; padding: 18px 24px; display: flex; align-items: center; justify-content: center; gap: 14px; margin-bottom: 28px; flex-wrap: wrap }
.sgs-social-proof__inner { max-width: 960px; margin: 0 auto }
.sgs-social-proof { background: var(--surface-alt); padding: 64px 20px }
.sgs-social-proof__inner { max-width: 960px; margin: 0 auto }
.sgs-social-proof h2 { font-size: 28px; font-weight: 600; color: var(--text); margin-bottom: 6px; text-align: center }
.sgs-social-proof .sgs-section-heading__sub { font-size: 16px; color: var(--text-muted); text-align: center; margin-bottom: 32px }
.sgs-social-proof__trustpilot-bar { background: white; border: 1px solid var(--border); border-radius: 10px; padding: 18px 24px; display: flex; align-items: center; justify-content: center; gap: 14px; margin-bottom: 28px; flex-wrap: wrap }
.sgs-social-proof__trustpilot-logo { font-size: 13px; font-weight: 700; color: #00B67A }
.sgs-social-proof__trustpilot-stars { font-size: 20px; color: #00B67A }
.sgs-social-proof__trustpilot-text { font-size: 13px; color: var(--text-muted) }
@media (min-width: 640px) :: .sgs-social-proof h2 { font-size: 36px }
